# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    # Get the request from the event
    request = event['Records'][0]['cf']['request']
    
    # Get headers from the request
    headers = request['headers']
    
    # Initialize context data
    context_data = {}
    
    # Check for enrichment URLs in headers
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        
        for url_header in enrich_urls:
            url = url_header['value']
            
            try:
                # Make HTTP request to fetch data
                response = requests.get(url, timeout=5)
                
                if response.status_code == 200:
                    # Parse response based on content type
                    content_type = response.headers.get('content-type', '')
                    
                    if 'application/json' in content_type:
                        context_data[url] = response.json()
                    else:
                        context_data[url] = response.text
                else:
                    context_data[url] = f"Error: HTTP {response.status_code}"
                    
            except Exception as e:
                context_data[url] = f"Error: {str(e)}"
    
    # Add context data to request headers for origin
    if context_data:
        context_header = json.dumps(context_data)
        request['headers']['x-enrich-context'] = [{
            'key': 'X-Enrich-Context',
            'value': context_header
        }]
    
    # Return modified request
    return request